SELECT COUNT(*) 
FROM frpm 
WHERE "County Name" = 'Amador' AND "Low Grade" = '9' AND "High Grade" = '12';

SELECT DISTINCT a.account_id
FROM account a
WHERE a.frequency = 'POPLATEK MESICNE';

SELECT 
    (COUNT(CASE WHEN card.type = 'gold' AND card.issued < '1998-01-01' THEN 1 END) * 100.0 / COUNT(*)) AS gold_percentage
FROM card;

SELECT (SUM(CASE WHEN district.A3 = 'North Bohemia' THEN district.A16 ELSE 0 END) - 
        SUM(CASE WHEN district.A3 = 'East Bohemia' THEN district.A16 ELSE 0 END)) AS crime_difference
FROM district;

SELECT AVG(o_count) FROM (
  SELECT molecule_id, COUNT(*) as o_count 
  FROM atom 
  WHERE element = 'O' AND molecule_id IN (
    SELECT molecule_id 
    FROM bond 
    WHERE bond_type = '-'
  )
  GROUP BY molecule_id
) t;

SELECT c.bond_id 
FROM connected c, atom a 
WHERE a.atom_id = 'TR000_2' AND c.atom_id2 = a.atom_id;

SELECT ROUND(CAST((COUNT(CASE WHEN a.element = 'h' THEN 1 END) * 100.0) AS DECIMAL(5,4)) / COUNT(*), 4) as percentage 
FROM atom a 
WHERE molecule_id = 'TR206';

SELECT COUNT(*) 
FROM atom 
WHERE element IN ('C', 'H');

SELECT CASE WHEN label = '+' THEN 'Yes' ELSE 'No' END AS is_carcinogenic 
FROM molecule 
WHERE molecule_id = 'TR124';

SELECT element 
FROM atom 
WHERE atom_id = 'TR000_1';

SELECT (COUNT(CASE WHEN T2.language = 'Chinese Simplified' THEN 1 ELSE NULL END) * 100.0 / COUNT(T1.id)) AS percentage
FROM cards AS T1
JOIN foreign_data AS T2 ON T1.uuid = T2.uuid;

SELECT COUNT(DISTINCT "type") 
FROM "cards" 
WHERE "artist" = 'Aaron Boyd';

SELECT COUNT(*) 
FROM cards 
WHERE originalType = 'Summon - Angel' AND subtypes != 'Angel';

SELECT COUNT(*) 
FROM cards 
WHERE availability LIKE '%paper%' AND hand = '3';

SELECT artist 
FROM cards 
WHERE flavorName = 'Battra, Dark Destroyer';

SELECT (COUNT(CASE WHEN cardKingdomFoilId IS NOT NULL AND cardKingdomId IS NOT NULL THEN 1 END) * 100.0 / COUNT(*)) AS percentage 
FROM cards 
WHERE setCode = 'CSP';

SELECT COUNT(*) 
FROM votes 
WHERE UserId = 58 AND CreationDate = '2010-07-19';

SELECT ViewCount 
FROM posts 
WHERE Title = 'Integration of Weka and/or RapidMiner into Informatica PowerCenter/Developer';

SELECT Text 
FROM comments 
WHERE Score = 17;

SELECT c.Text FROM comments c 
JOIN posts p ON c.PostId = p.Id 
WHERE p.Title = 'Why square the difference instead of taking the absolute value in standard deviation?';

SELECT CAST(COUNT(DISTINCT CASE WHEN b.Name = 'Teacher' THEN b.UserId ELSE NULL END) AS REAL) * 100 / COUNT(DISTINCT u.Id) AS TeacherBadgePercentage
FROM badges b
JOIN users u ON b.UserId = u.Id;

SELECT COUNT(*) 
FROM users 
WHERE Reputation > 2000 AND Views > 1000;

SELECT COUNT(*) 
FROM posts 
WHERE ViewCount > 35000 AND CommentCount = 0;

SELECT COUNT(DISTINCT UserId) 
FROM badges 
WHERE Name = 'Citizen Patrol';

SELECT COUNT(*) 
FROM tags 
WHERE Id < 15 AND Count <= 20;

SELECT ExcerptPostId, WikiPostId 
FROM tags 
WHERE TagName = 'sample';

SELECT r.race FROM superhero s 
JOIN race r ON s.race_id = r.id 
WHERE s.superhero_name = 'Copycat';

SELECT 
    (SELECT COUNT(*) FROM superhero sh JOIN publisher p ON sh.publisher_id = p.id WHERE p.publisher_name = 'Marvel Comics') -
    (SELECT COUNT(*) FROM superhero sh JOIN publisher p ON sh.publisher_id = p.id WHERE p.publisher_name = 'DC Comics') AS difference;

SELECT 
    (SELECT weight_kg FROM superhero WHERE full_name = 'Emil Blonsky') - 
    (SELECT weight_kg FROM superhero WHERE full_name = 'Charles Chandler') AS weight_difference;

SELECT ROUND(100.0 * (COUNT(CASE WHEN c.colour = 'Blue' THEN 1 END) / COUNT(*)), 2) 
FROM superhero s 
JOIN colour c ON s.eye_colour_id = c.id;

SELECT superhero_name 
FROM superhero 
WHERE full_name = 'Charles Chandler';

SELECT nationality 
FROM drivers 
WHERE dob = (SELECT MIN(dob) FROM drivers);

SELECT COUNT(*) 
FROM circuits 
WHERE location = 'Adelaide' AND country = 'Australia';

SELECT SUM(wins) FROM (
    SELECT cs.wins 
    FROM constructorStandings cs
    JOIN driverStandings ds ON cs.raceId = ds.raceId AND cs.position = 91
    GROUP BY cs.constructorId, cs.raceId
) AS wins;

SELECT MIN(fastestLapTime) AS fastest_lap_time 
FROM results 
WHERE fastestLap = 1;

SELECT AVG(height) AS average_height 
FROM Player 
WHERE birthday >= '1990-01-01' AND birthday < '1996-01-01';

SELECT 
    (SELECT AVG(ball_control) FROM Player_Attributes pa JOIN Player p ON pa.player_api_id = p.id WHERE p.player_name = 'Abdou Diallo') -
    (SELECT AVG(ball_control) FROM Player_Attributes pa JOIN Player p ON pa.player_api_id = p.id WHERE p.player_name = 'Aaron Appindangoye');

SELECT (COUNT(CASE WHEN Admission = '+' THEN 1 END) * 100.0) / COUNT(*) AS percentage_inpatient
FROM Patient
WHERE Birthday BETWEEN '1930-01-01' AND '1940-12-31';

SELECT (CAST(COUNT(DISTINCT CASE WHEN p.SEX = 'F' AND (l.TP < 6.0 OR l.TP > 8.5) THEN l.ID END) AS REAL) / CAST(COUNT(DISTINCT CASE WHEN p.SEX = 'F' THEN l.ID END) AS REAL)) * 100 AS percentage 
FROM Laboratory l
JOIN Patient p ON l.ID = p.ID;

SELECT CASE WHEN "T-CHO" < 250 THEN 'Normal' ELSE 'Not Normal' END AS cholesterol_status
FROM "Laboratory"
WHERE "ID" = 2927464 AND "Date" = '1995-09-04';

SELECT CAST((COUNT(CASE WHEN Diagnosis = 'BEHCET' THEN 1 END) * 100.0) / COUNT(*) AS REAL)
FROM Patient 
WHERE SEX = 'M' AND YEAR(`First Date`) = 1981;

SELECT (COUNT(DISTINCT CASE WHEN l.GOT >= 60 AND p.Diagnosis = 'SLE' THEN l.ID END) * 100.0 / COUNT(DISTINCT CASE WHEN l.GOT >= 60 THEN l.ID END)) as percentage
FROM Laboratory l
JOIN Patient p ON l.ID = p.ID;

SELECT COUNT(*) 
FROM member 
WHERE position = 'President';

SELECT (CAST(SUM(CASE WHEN type = 'Community Service' THEN 1 ELSE 0 END) AS REAL) * 100 / COUNT(event_id)) AS percentage
FROM event
WHERE event_date BETWEEN '2019-01-01' AND '2019-12-31';

SELECT MAX(budget.amount)
FROM budget
WHERE budget.category = 'Food';

SELECT (SUM(CASE WHEN m.position = 'Member' AND ma.major_name = 'Business' THEN 1 ELSE 0 END) * 100.0 / COUNT(*)) AS percentage
FROM member m
JOIN major ma ON m.link_to_major = ma.major_id;

SELECT DISTINCT state 
FROM zip_code 
WHERE type = 'PO Box';

SELECT (COUNT(CASE WHEN b.remaining < 0 THEN 1 END) * 100.0 / COUNT(e.event_id)) AS over_budget_percentage
FROM event e
LEFT JOIN budget b ON e.event_id = b.link_to_event;

SELECT event_id, location, status 
FROM event 
WHERE event_date BETWEEN '2019-11-01' AND '2020-03-31';

SELECT 
    (SELECT COUNT(*) FROM gasstations WHERE Country = 'CZE' AND Segment = 'Discount') -
    (SELECT COUNT(*) FROM gasstations WHERE Country = 'SVK' AND Segment = 'Discount') AS difference;

SELECT (COUNT(CASE WHEN Currency = 'Euro' THEN CustomerID ELSE NULL END) * 100.0 / COUNT(CustomerID)) AS PercentageOfKAMUsingEuro
FROM customers
WHERE Segment = 'KAM';

SELECT MAX(Consumption) 
FROM yearmonth 
WHERE Date LIKE '2012%';

SELECT AVG(Amount * Price) AS AverageTotalPrice
FROM transactions_1k
WHERE Date LIKE '2012-01%';
